import{_ as r,o as e,c as a,a2 as o}from"./chunks/framework.pnUkSPAE.js";const n="/diagrams/transformer-arch.svg",m=JSON.parse('{"title":"1.1 Transformer 架构 + 1.4 开源vs闭源选型","description":"","frontmatter":{"title":"1.1 Transformer 架构 + 1.4 开源vs闭源选型"},"headers":[],"relativePath":"guide/stage1-transformer.md","filePath":"guide/stage1-transformer.md"}'),d={name:"guide/stage1-transformer.md"};function s(l,t,i,h,g,u){return e(),a("div",null,[...t[0]||(t[0]=[o('<blockquote><p>[日期] 预计学习时间：30-40 小时</p></blockquote><h2 id="_1-1-transformer-架构" tabindex="-1">1.1 Transformer 架构 <a class="header-anchor" href="#_1-1-transformer-架构" aria-label="Permalink to &quot;1.1 Transformer 架构&quot;">​</a></h2><p>Transformer 是现代大语言模型的基础架构，2017 年由 Google 在论文《Attention Is All You Need》中提出。你不需要从头推导数学公式，但需要理解以下核心概念：</p><p><strong>自注意力机制（Self-Attention）：</strong> 模型在处理一个词时，会&quot;关注&quot;输入序列中的其他词，计算它们之间的相关性。</p><p><strong>核心组件：</strong></p><ul><li><strong>Tokenization（分词）：</strong> BPE 是主流方法，GPT 系列使用 tiktoken 库。中文字符约 1-3 个 token</li><li><strong>Embedding（词嵌入）：</strong> 将 token 转换为高维向量（如 4096 维）</li><li><strong>多头注意力（Multi-Head Attention）：</strong> 同时从多个&quot;视角&quot;关注输入</li><li><strong>位置编码（Positional Encoding）：</strong> 告诉模型词的位置信息</li><li><strong>FFN（前馈网络）：</strong> 每一层中的全连接网络</li></ul><p><strong>编码器 vs 解码器架构对比：</strong></p><img src="'+n+'" alt="Transformer三大架构分支" style="max-width:100%;height:auto;"><table tabindex="0"><thead><tr><th>架构</th><th>代表模型</th><th>适用任务</th><th>大厂考察重点</th></tr></thead><tbody><tr><td>Encoder-only</td><td>BERT</td><td>分类、NER、相似度</td><td>理解原理即可</td></tr><tr><td>Decoder-only</td><td>GPT、DeepSeek、Qwen</td><td>生成、对话、Agent</td><td><strong>重点掌握</strong></td></tr><tr><td>Encoder-Decoder</td><td>T5、BART</td><td>翻译、摘要</td><td>了解即可</td></tr></tbody></table><h2 id="_1-4-开源-vs-闭源模型选型" tabindex="-1">1.4 开源 vs 闭源模型选型 <a class="header-anchor" href="#_1-4-开源-vs-闭源模型选型" aria-label="Permalink to &quot;1.4 开源 vs 闭源模型选型&quot;">​</a></h2><table tabindex="0"><thead><tr><th>维度</th><th>闭源 API</th><th>开源自部署</th></tr></thead><tbody><tr><td>成本</td><td>按量付费，初期低</td><td>GPU 硬件成本高</td></tr><tr><td>延迟</td><td>网络依赖</td><td>可控</td></tr><tr><td>数据安全</td><td>数据出域</td><td>数据不出域</td></tr><tr><td>定制化</td><td>有限</td><td>完全可控</td></tr><tr><td>大厂偏好</td><td>原型开发、快速验证</td><td>生产部署、成本敏感</td></tr></tbody></table><p><strong>建议：</strong> 开发阶段用闭源 API，面试准备了解国产模型生态，生产部署评估开源模型。</p><h3 id="学习资料清单" tabindex="-1">学习资料清单 <a class="header-anchor" href="#学习资料清单" aria-label="Permalink to &quot;学习资料清单&quot;">​</a></h3><p><strong>视频课程：</strong></p><ul><li>3Blue1Brown《But what is a GPT?》系列（B站有中文字幕）</li><li>Andrej Karpathy《Let&#39;s build GPT: from scratch》（YouTube，B站有搬运）</li><li>李沐《Transformer 论文逐行精读》（B站搜索&quot;李沐 transformer&quot;）</li></ul><p><strong>论文：</strong></p><ul><li>&quot;Attention Is All You Need&quot;（Transformer 原始论文）：<a href="https://arxiv.org/abs/1706.03762" target="_blank" rel="noreferrer">https://arxiv.org/abs/1706.03762</a></li><li>&quot;The Illustrated Transformer&quot; by Jay Alammar（图解版）：<a href="https://jalammar.github.io/illustrated-transformer/" target="_blank" rel="noreferrer">https://jalammar.github.io/illustrated-transformer/</a></li></ul><p><strong>GitHub：</strong></p><ul><li><code>karpathy/nanoGPT</code> — 最小化 GPT 训练代码：<a href="https://github.com/karpathy/nanoGPT" target="_blank" rel="noreferrer">https://github.com/karpathy/nanoGPT</a></li><li><code>deepseek-ai/DeepSeek-V3</code> — DeepSeek 官方仓库：<a href="https://github.com/deepseek-ai/DeepSeek-V3" target="_blank" rel="noreferrer">https://github.com/deepseek-ai/DeepSeek-V3</a></li><li><code>QwenLM/Qwen2.5</code> — 通义千问官方仓库：<a href="https://github.com/QwenLM/Qwen2.5" target="_blank" rel="noreferrer">https://github.com/QwenLM/Qwen2.5</a></li></ul><p><strong>书籍：</strong></p><ul><li>《动手学深度学习》（李沐）— d2l.ai 在线免费</li><li>《Build a Large Language Model (From Scratch)》by Sebastian Raschka</li></ul>',21)])])}const c=r(d,[["render",s]]);export{m as __pageData,c as default};
